SELECT param_id, name, description, datatype, default_value, mutability, param_category, is_required, min_value, max_value, validation_regex, backend_id
FROM configuration_parameters
WHERE datatype = 'String' AND is_required = 0 AND param_category = 'Compression';

SELECT COUNT(param_id)
FROM configuration_parameters
WHERE is_required = 1 AND param_category = 'Storage';

SELECT ua.username, ua.role, p.can_edit, p.can_view 
FROM user_accounts ua 
LEFT JOIN permissions p ON ua.role = p.role;

SELECT cp.name, cp.datatype
FROM configuration_parameters cp
WHERE cp.is_required = 1 AND cp.default_value IS NULL;

SELECT COUNT(DISTINCT user_id) 
FROM configuration_changes
WHERE change_date >= DATETIME('now', '-7 days');

SELECT param_id, name
FROM configuration_parameters
WHERE is_required = 1 AND mutability = 'FIXED';

SELECT audit_id, param_id, changed_value, change_date, changed_by, change_reason, ip_address 
FROM audit_logs 
WHERE param_id = 0 AND backend_id = 0;

SELECT changed_value, change_date
FROM audit_logs
WHERE param_id = (SELECT param_id FROM configuration_parameters WHERE name = 'storage.hbase.compression-algorithm');

SELECT name, default_value, datatype, min_value, max_value
FROM configuration_parameters
WHERE param_id = 1;
